import{_ as e,o as r,c as t,a3 as i}from"./chunks/framework.BsQeBrPm.js";const p=JSON.parse('{"title":"計算機の使い方","description":"","frontmatter":{},"headers":[],"relativePath":"guide/calculator-guide.md","filePath":"guide/calculator-guide.md"}'),o={name:"guide/calculator-guide.md"};function l(n,a,h,d,s,c){return r(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="計算機の使い方" tabindex="-1">計算機の使い方 <a class="header-anchor" href="#計算機の使い方" aria-label="Permalink to &quot;計算機の使い方&quot;">​</a></h1><p>Anno 117 生産チェーン計算機の基本的な操作方法を説明します。</p><h2 id="基本的な流れ" tabindex="-1">基本的な流れ <a class="header-anchor" href="#基本的な流れ" aria-label="Permalink to &quot;基本的な流れ&quot;">​</a></h2><h3 id="_1-商品を選ぶ" tabindex="-1">1. 商品を選ぶ <a class="header-anchor" href="#_1-商品を選ぶ" aria-label="Permalink to &quot;1. 商品を選ぶ&quot;">​</a></h3><p>画面左のパネルにカテゴリ別の商品ツリーが表示されています。目的の商品をクリックすると、その商品の生産チェーンが中央パネルに表示されます。</p><h3 id="_2-生産チェーンを確認する" tabindex="-1">2. 生産チェーンを確認する <a class="header-anchor" href="#_2-生産チェーンを確認する" aria-label="Permalink to &quot;2. 生産チェーンを確認する&quot;">​</a></h3><p>中央パネルには、選択した商品を生産するために必要な建物と依存関係がグラフで表示されます。各ノードには建物名・必要件数が表示されます。</p><p>グラフの操作：</p><ul><li><strong>移動</strong>（デスクトップ）: 左クリックしたままドラッグ</li><li><strong>移動</strong>（タッチ）: 1本指でドラッグ</li><li><strong>拡大縮小</strong>（デスクトップ）: マウスホイール</li><li><strong>拡大縮小</strong>（タッチ）: 2本指でピンチ</li></ul><h3 id="_3-数量を調整する" tabindex="-1">3. 数量を調整する <a class="header-anchor" href="#_3-数量を調整する" aria-label="Permalink to &quot;3. 数量を調整する&quot;">​</a></h3><p>画面右のパネルで生産量の倍率を調整できます。目標とする生産数に合わせて必要な建物数が再計算されます。</p><h2 id="その他の機能" tabindex="-1">その他の機能 <a class="header-anchor" href="#その他の機能" aria-label="Permalink to &quot;その他の機能&quot;">​</a></h2><h3 id="地域切り替え" tabindex="-1">地域切り替え <a class="header-anchor" href="#地域切り替え" aria-label="Permalink to &quot;地域切り替え&quot;">​</a></h3><p>ヘッダーの地域ボタン（旗アイコン）から <strong>ラティウム / アルビオン</strong> を切り替えられます。各地域固有の商品や建物が反映されます。</p><h3 id="言語切り替え" tabindex="-1">言語切り替え <a class="header-anchor" href="#言語切り替え" aria-label="Permalink to &quot;言語切り替え&quot;">​</a></h3><p>ヘッダーの「EN / 日本語」ボタンで表示言語を切り替えられます。</p><h3 id="建設コスト・維持費" tabindex="-1">建設コスト・維持費 <a class="header-anchor" href="#建設コスト・維持費" aria-label="Permalink to &quot;建設コスト・維持費&quot;">​</a></h3><p>画面下部に、選択中の生産チェーン全体の建設コストと維持費の合計が表示されます。</p><h2 id="wikiへ戻る" tabindex="-1">Wikiへ戻る <a class="header-anchor" href="#wikiへ戻る" aria-label="Permalink to &quot;Wikiへ戻る&quot;">​</a></h2><p>ヘッダー右上の「Wiki」リンクから Wiki トップへ戻ることができます。また、Wiki の商品一覧・生産チェーン一覧ページにある「計算」リンクから、対応する商品を選択した状態で計算機を開けます。</p>',20)])])}const _=e(o,[["render",l]]);export{p as __pageData,_ as default};
